export const detectBrandKey = (stationName: string): BrandKey => {
  const n = stationName.toLowerCase();
  if (n.includes('shell')) return 'shell';
  if (n.includes('esso') || n.includes('exxon')) return 'esso';
  if (n.includes('mobil')) return 'mobil';
  if (n.includes('chevron')) return 'chevron';
  if (n.includes('petro') && n.includes('canada')) return 'petro_canada';
  if (n.includes('super') && n.includes('save') && n.includes('gas')) return 'super_save_gas';
  return 'unknown';
};

export const svgToDataUrl = (svg: string) =>
  `data:image/svg+xml;utf8,${encodeURIComponent(svg)}`;
